#include <bits/stdc++.h>
using namespace std;
int main(){int n,m;scanf("%d %d",&n,&m);vector<long long>a(n);long long sum=0,mx=0;for(auto&x:a){scanf("%lld",&x);sum+=x;mx=max(mx,x);}long long lo=mx,hi=sum,ans=sum;while(lo<=hi){long long mid=(lo+hi)/2,cur=0;int cnt=1;for(auto x:a){if(cur+x>mid){cnt++;cur=x;}else cur+=x;}if(cnt<=m){ans=mid;hi=mid-1;}else lo=mid+1;}printf("%lld\n",ans);}
